#include<bits/stdc++.h>
#define list mylist
using namespace std;
struct list_node
{
    long long pre,val;
}a[4000010];
long long tot_list,q[4000010],query_tot;
long long newlistnode(long long x)
{
    a[++tot_list].val=x;
    return tot_list;
}
struct list
{
    long long head,tail,siz;
    void push_back(long long x)
    {
        a[x].pre=tail;
        tail=x;
        if(siz==0)
        {
            head=x;
        }
        siz++;
    }
    void pop_back()
    {
        tail=a[tail].pre;
        siz--;
        if(siz==0)
        {
            head=0;
        }
    }
    void merge(list x,list y)
    {
        head=(x.siz?x.head:y.head);
        tail=(y.siz?y.tail:x.tail);
        if(y.head)
        {
            a[y.head].pre=x.tail;
        }
        siz=x.siz+y.siz;
    }
}l[4000010];
struct segtree_node
{
    long long lson,rson;
    long long sum;
}t[4000010];
long long segtree_tot;
void update(long long &x,long long l,long long r,long long p,long long v)
{
    if(x==0)
    {
        x=++segtree_tot;
        t[x].lson=t[x].rson=t[x].sum=0;
    }
    t[x].sum+=v;
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    if(p<=mid)
    {
        update(t[x].lson,l,mid,p,v);
    }
    else
    {
        update(t[x].rson,mid+1,r,p,v);
    }
}
long long getsum(long long x,long long l,long long r,long long p)
{
    if(x==0)
    {
        return 0;
    }
    if(l==r)
    {
        return t[x].sum;
    }
    long long mid=(l+r)>>1;
    if(p<=mid)
    {
        return getsum(t[x].lson,l,mid,p);
    }
    else
    {
        return getsum(t[x].rson,mid+1,r,p);
    }
}
long long query(long long l,long long r,long long k)
{
    if(l==r)
    {
        return l;
    }
    long long mid=(l+r)>>1;
    long long sum=0;
    for(long long i=1;i<=query_tot;i++)
    {
        sum+=t[t[q[i]].lson].sum;
    }
    if(k<=sum)
    {
        for(long long i=1;i<=query_tot;i++)
        {
            q[i]=t[q[i]].lson;
        }
        return query(l,mid,k);
    }
    else
    {
        for(long long i=1;i<=query_tot;i++)
        {
            q[i]=t[q[i]].rson;
        }
        return query(mid+1,r,k-sum);
    }
}
long long merge(long long x,long long y,long long l,long long r)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    t[x].sum+=t[y].sum;
    if(l==r)
    {
        return x;
    }
    long long mid=(l+r)>>1;
    t[x].lson=merge(t[x].lson,t[y].lson,l,mid);
    t[x].rson=merge(t[x].rson,t[y].rson,mid+1,r);
    return x;
}
long long root[4000010],p[4000010],n,Q;
int main()
{
    scanf("%lld%lld",&n,&Q);
    for(long long i=1;i<=n;i++)
    {
        long long c;
        scanf("%lld",&c);
        while(c--)
        {
            long long x;
            scanf("%lld",&x);
            l[i].push_back(newlistnode(x));
            update(root[i],1,n+Q,x,1);
        }
    }
    for(long long _=1;_<=Q;_++)
    {
        long long op;
        scanf("%lld",&op);
        if(op==1)
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            l[x].push_back(newlistnode(y));
            update(root[x],1,n+Q,y,1);
        }
        else if(op==2)
        {
            long long x;
            scanf("%lld",&x);
            update(root[x],1,n+Q,a[l[x].tail].val,-1);
            l[x].pop_back();
        }
        else if(op==3)
        {
            scanf("%lld",&query_tot);
            long long sum=0;
            for(long long i=1;i<=query_tot;i++)
            {
                long long x;
                scanf("%lld",&x);
                q[i]=root[x];
                sum+=l[x].siz;
                p[i]=x;
            }
            // printf("sum=%lld\n",sum);
            long long tmp=query(1,n+Q,(sum+1)>>1);
            long long sum1=0;
            for(long long i=1;i<=query_tot;i++)
            {
                sum1+=getsum(root[p[i]],1,n+Q,tmp);
            }
            if(sum1*2>sum)
            {
                printf("%lld\n",tmp);
            }
            else
            {
                printf("-1\n");
            }
        }
        else
        {
            long long x,y,z;
            scanf("%lld%lld%lld",&x,&y,&z);
            l[z].merge(l[x],l[y]);
            root[z]=merge(root[x],root[y],1,n+Q);
        }
    }
    return 0;
}
